get headers(): Headers {
  const cache = (this as LightResponse)[cacheKey] as InternalCache
  if (cache) {
    if (!(cache[2] instanceof Headers)) {
      cache[2] = new Headers(
        (cache[2] ||
          (cache[1] === null ? undefined : { 'content-type': defaultContentType })) as HeadersInit
      )
    }
    return cache[2]
  }
  return this[getResponseCache]().headers
}

