{
  overrideGlobalObjects: false,
  errorHandler: (e) => {
    let err: Error
    if (e instanceof Error) {
      err = e
      server.ssrFixStacktrace(err)
    } else if (typeof e === 'string') {
      err = new Error(`The response is not an instance of "Response", but: ${e}`)
    } else {
      err = new Error(`Unknown error: ${e}`)
    }

    next(err)
  },
}

const nonSystemLabels = issueLabels
    .map((label) => {
      if (typeof label === "string") {
        return { name: label, color: "#6B7280" };
      }
      return {
        name: label.name,
        color: label.color ? `#${label.color}` : "#6B7280",
      };
    })
    .filter(
      (label) =>
        label.name &&
        !label.name.startsWith("priority:") &&
        !label.name.startsWith("status:"),
    ) as Array<{ name: string; color: string }>;
